            企事業單位的全稱或簡稱
          </el-radio>
          <el-radio label="1">
            工信部備案網站的全稱或簡稱
          </el-radio>
          <el-radio label="2">
            App 應用的全稱或簡稱
          </el-radio>
          <el-radio label="3">
            公眾號或小程序的全稱或簡稱
          </el-radio>
          <el-radio label="4">
            電商平台店鋪名的全稱或簡稱
          </el-radio>
          <el-radio label="5">
            商標名的全稱或簡稱
          </el-radio>
        </el-radio-group>
      </el-form-item>
      <el-form-item
        label="申請說明"
        prop="remark"
      >
        <el-input
          v-model="form.remark"
          :disabled="disabled"
          type="textarea"
          :rows="8"
          maxlength="200"
          show-word-limit
          placeholder="詳細描述您的業務使用場景或簽名用途，可填寫企業官網連結，工信部備案網站域名，已上線應用在任一應用商店顯示頁連結，公眾號或小程序全稱，任一電商店鋪顯示頁連結，已註冊商標名等，可有效提升通過率，長度不超過 200 個字符。"
        />
      </el-form-item>
      <el-form-item label="證明文件">
        <div
          class="upload-box"
          @click="handleImgPicker('sign_file')"
        >
          <template v-if="form.sign_file">
            <img
              v-if="form.sign_file"
              class="avatar"
              :src="form.sign_file"
            >
            <i
              v-if="$route.query.type != 'detail'"
              class="el-icon-error close"
              @click.stop="deleteUrl('sign_file')"
            />
          </template>
          <i
            v-else
            slot="default"
            class="el-icon-plus"
          />
        </div>
        <span>簽名歸屬方的三證合一</span>
        <ul class="tips">
          <li>
            說明：個別場景下，申請簽名需要上傳證明文件。詳細說明，請參見
            <a
              target="_blank"
              href="https://help.aliyun.com/document_detail/108076.htm?spm=a2c4g.11186623.0.0.236c3d26hyj4yl"
            >短信簽名規範。</a>
          </li>
          <li>支持 JPG、PNG、GIF 或 JPEG 格式的圖片，圖片不超過 2 MB。</li>
        </ul>
      </el-form-item>
      <el-form-item label="委托授權書">
        <div
          class="upload-box"
          @click="handleImgPicker('delegate_file')"
        >
          <template v-if="form.delegate_file">
            <img
              class="avatar"
              :src="form.delegate_file"
            >
            <i
              v-if="$route.query.type != 'detail'"
              class="el-icon-error close"
              @click.stop="deleteUrl('delegate_file')"
            />
          </template>
          <i
            v-else
            slot="default"
            class="el-icon-plus"
          />
        </div>

        <ul class="tips">
          <li>
            說明：
            如果簽名用途為他用或個人認證用戶的自用簽名來源為企事業單位名時，還需上傳證明文件和委托授權書，詳情請參見
            <a
              target="_blank"
              href="https://help.aliyun.com/document_detail/108076.htm?spm=a2c4g.11186623.0.0.236c25a11W2iBL"
            >
              證明文件 </a>和
            <a
              target="_blank"
              href="https://help.aliyun.com/document_detail/56741.htm?spm=a2c4g.11186623.0.0.236c25a1zODsEU"
            >授權委托書</a>。
          </li>
          <li>支持 JPG、PNG、GIF 或 JPEG 格式的圖片，圖片不超過 2 MB。</li>
        </ul>
      </el-form-item>
      <el-form-item v-if="$route.query.type !== 'detail'">
        <loadingBtn
          ref="loadingBtn"
          @clickHandle="submitForm('form')"
        />
        <el-button @click="fnBack">
          取消
        </el-button>
        <ul class="tips">
          <li>預計兩小時完成審核，政企簽名預計在 48 小時工作時間內審核</li>
          <li>審核工作時間：周一至周日 9:00-23:00（法定節日順延）</li>
        </ul>
      </el-form-item>
    </el-form>
    <!-- 圖片選擇 -->
    <imgPicker
      :dialog-visible="imgDialog"
      :sc-status="isGetImage"
      @chooseImg="pickImg"
      @closeImgDialog="closeImgDialog"
    />

    <!-- result -->
    <el-dialog
      :visible="resultVisible"
      class="result"
      :show-close="false"
    >
      <el-result
        icon="success"
        title="提交成功"
        sub-title="請根據提示進行操作"
      >
        <template slot="subTitle">
          <h5>簽名已提交審核，審核結果可在簽名列表中查看。</h5>
          <ul class="tips">
            <li>預計兩小時完成審核，政企簽名預計在 48 小時工作時間內審核</li>
            <li>審核工作時間：周一至周日 9:00-23:00（法定節日順延）</li>
          </ul>
        </template>
        <template slot="extra">
          <el-button
            type="primary"
            size="medium"
            @click="fnBack"
          >
            返回列表
          </el-button>
          <el-button
            v-if="!$route.query.type"
            size="medium"
            @click="fnAgain"
          >
            再新增一個簽名
          </el-button>
        </template>
      </el-result>
    </el-dialog>
  </div>
</template>

<script>
import { requiredRules, MaxRules, MinRules } from '@/utils/validate'
import imgPicker from '@/components/imageselect'
import loadingBtn from '@/components/loading-btn'
import { setTheNewSignature, getTheSignature, editTheSignature } from '@/api/sms'

export default {
  components: {
    imgPicker,
    loadingBtn
  },
  data () {
    return {
      // 頁面狀態
      disabled: false,
      disabled_edit: false,
      // 圖片選擇
      imgDialog: false,
      isGetImage: false,
      pickerImgType: '',
      // result
      resultVisible: false,
      form: {
        sign_name: '', //簽名名稱
        sign_source: '',
        remark: '',
        sign_file: '', // 證明文件
        delegate_file: '' //委托授權書
      },
      rules: {
        sign_name: [requiredRules('簽名名稱'), MaxRules(12), MinRules(2)],
        sign_source: [requiredRules('簽名來源', 'change')],
        remark: [requiredRules('申請說明'), MaxRules(200)]
      }
    }
  },
  mounted () {
    this.init()
  },
  methods: {
    async init () {
      const { type, id } = this.$route.query
      console.log(type, id)

      if (type) {
        const result = await getTheSignature({ id })
        this.resultHandler(result)
        if (type == 'detail') {
          this.disabled = true
        }

        if (type == 'edit') {
          this.disabled_edit = true
        }
      }
    },
    resultHandler (result) {
      const { sign_name, sign_source, remark, sign_file, delegate_file } = result.data.data
      console.log(sign_name)
      this.form = {
        sign_name,
        sign_source: sign_source + '',
        remark,
        sign_file,
        delegate_file
      }
    },
    submitForm (formName) {
      const { type, id } = this.$route.query
      this.$refs[formName].validate(async (valid) => {
        if (valid) {
          try {
            if (type == 'edit') {
              const result = await editTheSignature({ id, ...this.form })
              this.submitFormResult(result)
            } else {
              const result = await setTheNewSignature(this.form)
              this.submitFormResult(result)
            }
          } catch (error) {
            this.$refs['loadingBtn'].closeLoading()
          }
        } else {
          console.log('error submit!!')
          this.$refs['loadingBtn'].closeLoading()
          return false
        }
      })
    },
    submitFormResult (result) {
      if (result.data.data.status) {
        this.resultVisible = true
      }
      this.$refs['loadingBtn'].closeLoading()
    },
    fnBack () {
      this.$router.push({
        path: `/setting/datamessage/ali_sms/sms_signatures`
      })
    },
    fnAgain () {
      this.resultVisible = false
      this.$refs['form'].resetFields()
      this.form.sign_file = ''
      this.form.delegate_file = ''
    },
    /* -------------------------圖片選擇------------------------- */
    pickImg ({ url }) {
      if (url && this.pickerImgType) {
        const that = this.form
        that[this.pickerImgType] = url
        this.imgDialog = false
      }
    },
    closeImgDialog () {
      this.imgDialog = false
      this.isGetImage = false
    },
    handleImgPicker (pickerImgType) {
      if (!this.disabled) {
        this.pickerImgType = pickerImgType
        this.imgDialog = true
        this.isGetImage = true
      }
    },
    deleteUrl (url) {
      this.form[url] = ''
    }
    /* -------------------------圖片選擇------------------------- */
  }
}
</script>

